from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    from collections import defaultdict

    # Helper to join multiple items with commas and 'and'
    def join_items(items: list[str]) -> str:
        if not items:
            return ""
        if len(items) == 1:
            return items[0]
        return ", ".join(items[:-1]) + " and " + items[-1]

    # Simple phrase builder used for non‑main subjects
    def simple_phrase(_, pred: str, objs: list[str]) -> str:
        obj = objs[0] if objs else ""
        if pred == "birthDate":
            return f"was born on {obj}"
        if pred in ("birthYear", "birthPlace"):
            return f"was born in {obj}"
        if pred == "origin":
            return f"originates from {obj}"
        if pred == "genre":
            return f"performs {obj.lower()}"
        if pred == "instrument":
            return f"plays {obj}"
        if pred == "occupation":
            return f"works as {obj}"
        if pred == "nationality":
            return f"is {obj}"
        if pred == "associatedBand/associatedMusicalArtist":
            return f"is associated with {join_items(objs)}"
        if pred == "recordLabel":
            return f"is signed to {obj}"
        if pred == "activeYearsStartYear":
            return f"started career in {obj}"
        if pred == "activeYearsEndYear":
            return f"ended career in {obj}"
        if pred == "deathDate":
            return f"died on {obj}"
        if pred == "deathPlace":
            return f"died in {obj}"
        if pred == "alternativeName":
            return f"is also known as {obj}"
        if pred == "stylisticOrigin":
            return f"has stylistic origins in {join_items(objs)}"
        if pred == "musicFusionGenre":
            return f"has a fusion genre {join_items(objs)}"
        if pred == "derivative":
            return f"is a derivative of {join_items(objs)}"
        return f"{pred} {join_items(objs)}"

    # Group objects by (subject, predicate)
    groups = defaultdict(list)  # type: dict[tuple[str, str], list[str]]
    for t in triples:
        groups[(t.subject, t.predicate)].append(t.object)

    # Choose the first subject as the primary focus
    main_subject = triples[0].subject

    # Collect predicates for the main subject
    main_info: dict[str, list[str]] = {}
    for (sub, pred), objs in groups.items():
        if sub == main_subject:
            main_info[pred] = objs

    clauses: list[str] = []

    # Birth information
    if "birthDate" in main_info:
        clauses.append(f"was born on {main_info['birthDate'][0]}")

# EVOLVE-BLOCK-END

